# Path router: matches (method, path) against a typed route table and
# resolves to (controller, action, path_params).
#
# In real-blog this is generated by Rails from `config/routes.rb`'s
# `resources` DSL; in spinel-blog it's a flat data structure (see
# `config/routes.rb`). The eventual transpiler reproduces this shape
# from the DSL declarations.
#
# Route rows are typed `Route` instances (not `Hash[Symbol, untyped]`)
# so strict-typed targets (Rust, Crystal) compile against per-field
# types instead of falling through an `untyped` value channel. Path
# captures land as `Hash[String, String]` — URL segments are always
# strings.

module ActionDispatch
  module Router
    # One entry in the route table. Promoted from
    # `Hash[Symbol, String|Symbol]` to a typed class so each per-field
    # type is statically known. `verb` rather than `method` to avoid
    # shadowing Ruby's `Object#method` reflection method.
    #
    # Positional `initialize` (not kwarg) — the per-target emitters
    # convert def-time kwargs to positional but don't unpack kwarg-style
    # call sites; positional avoids the asymmetry on internal classes
    # like this one.
    class Route
      attr_reader :verb, :pattern, :controller, :action, :req_format, :int_params

      # `req_format` — the route-forced response format (Rails'
      # `get "/rss" => "home#index", :format => "rss"`), nil for the
      # common infer-from-path case. Named `req_format` (not `format`)
      # so targets whose stdlibs claim `format` never collide.
      #
      # `int_params` — space-joined names of path params constrained to
      # digit-only segments (Roda's `Integer` matcher, Rails digit-class
      # `constraints:`), e.g. `"id"` or `"article_id id"`; the empty
      # string for the unconstrained common case. Carried as a delimited
      # String rather than `Array[String]` so this optional positional
      # stays a single scalar type on strict/AOT targets — a `nil`-or-`[]`
      # optional tail collapses to `Any?`/a bare variadic on Swift,
      # Kotlin, Go, and Spinel. A candidate segment that isn't all digits
      # makes the route a non-match, so `/articles/12abc` falls through
      # to 404 instead of binding `id = "12abc"`.
      def initialize(verb, pattern, controller, action, req_format = nil, int_params = +"")
        @verb        = verb
        @pattern     = pattern
        @controller  = controller
        @action      = action
        @req_format  = req_format
        @int_params  = int_params
      end
    end

    # The result of a successful `Router.match` call: the resolved
    # controller symbol, action symbol, and captured path parameters.
    # Replaces the prior `{ controller:, action:, path_params: }` hash
    # return shape. Positional initialize, same rationale as Route.
    class MatchResult
      attr_reader :controller, :action, :path_params, :req_format

      def initialize(controller, action, path_params, req_format = nil)
        @controller  = controller
        @action      = action
        @path_params = path_params
        @req_format  = req_format
      end
    end

    # Match a request against the route table. Returns a `MatchResult`
    # on success; nil otherwise.
    #
    # Index-style loop (not `table.each do |...| ... return ... end`)
    # so the cross-target lowering doesn't have to model "return from
    # enclosing method out of an iterator block" — JS `forEach` can't
    # break out of the surrounding function and the body-walker would
    # silently strip the early-return.
    def self.match(method, path, table)
      method_upcase = method.to_s.upcase
      i = 0
      while i < table.length
        route = table[i]
        if route.verb.to_s == method_upcase
          params = match_pattern(route.pattern.to_s, path, route.int_params)
          unless params.nil?
            return MatchResult.new(route.controller, route.action, params, route.req_format)
          end
        end
        i += 1
      end
      nil
    end

    # Match a path against a pattern containing `:name` segments.
    # Returns a `Hash[String, String]` of captured params, or nil
    # if no match. No regex; segment-by-segment compare. Captures
    # are always string-to-string — URL segments are strings, and
    # the typed-hash form survives strict-typed targets (Crystal,
    # Rust). Callers index by string key (`params["id"]`).
    #
    # `int_params` (optional) is the route's space-joined digit-only
    # constraint list. A constrained `:name` segment whose value isn't
    # all digits makes the whole pattern a non-match — `Router.match`
    # keeps scanning and the request 404s. The check runs here on the
    # raw segment (`ap`, a non-nil String local) rather than after
    # capture so no target has to model `Hash#[]` returning nil.
    def self.match_pattern(pattern, path, int_params = +"")
      pattern_parts = pattern.split("/")
      path_parts    = path.split("/")
      return nil if pattern_parts.length != path_parts.length
      params = {}
      i = 0
      while i < pattern_parts.length
        pp = pattern_parts[i]
        ap = path_parts[i]
        if pp.start_with?(":")
          name = pp[1..]
          # `seg = ap.to_s` (not `digits_only(ap)` directly): some strict
          # emitters track a bare array-index local as nilable and coerce
          # it wrongly at a non-nilable call arg; routing the segment
          # through `to_s` first hands `digits_only` a definite String.
          seg = ap.to_s
          if int_constrained(int_params, name) && !digits_only(seg)
            return nil
          end
          params[name] = ap
        elsif pp != ap
          return nil
        end
        i += 1
      end
      params
    end

    # Is `name` one of the route's digit-constrained params?
    # `int_params` is the space-joined constraint list carried on
    # `Route`; the empty string means the route constrains nothing.
    # Membership by split + `==` scan (no `Array#include?`, no `Hash`
    # read) so it lowers cleanly to every target. Named without a `?`
    # suffix on purpose: the Elixir lowering appends `__loop` to a
    # while-loop method's own name, and `?` can only end an Elixir
    # identifier — `int_constrained?__loop` would fail to parse.
    def self.int_constrained(int_params, name)
      return false if int_params.empty?
      parts = int_params.split(" ")
      i = 0
      while i < parts.length
        return true if parts[i] == name
        i += 1
      end
      false
    end

    # All-digits check for constrained segments. No regex (the router
    # stays cross-target lowerable) and no `to_i` round-trip (it would
    # reject the leading zeros Roda's `Integer` matcher accepts —
    # `/articles/007` is id 7, not a 404). The digit test is an explicit
    # `String#==` fan-out rather than `"0123456789".include?(c)`: a
    # string *literal* receiver for `#include?` lowers to a struct call
    # on Elixir and an unsatisfiable `Pattern` bound on Rust, whereas
    # `==` against single-char literals is a proven strict-emitter shape.
    def self.digits_only(s)
      return false if s.empty?
      i = 0
      while i < s.length
        c = s[i, 1].to_s
        if c != "0" && c != "1" && c != "2" && c != "3" && c != "4" &&
           c != "5" && c != "6" && c != "7" && c != "8" && c != "9"
          return false
        end
        i += 1
      end
      true
    end
  end
end
